var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"…그리하여, 오늘 하루 동안 인공지능 주르를 대신해 내 일일 조수가 되어주기로 한 케이시 양이야.","JPN":"……というわけで、今日一日、J.O.U.Rの代わりに私の助手になってもらうケイシーね。","ENG":"...And so, this is Kaci, who will be my daily assistant for the day on behalf of the AI J.O.U.R.","TWN":"……於是今天一整天，卡西小姐將代替人工智慧J.O.U.R，成為我的臨時助手。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"잘…! 부탁드립니다!","JPN":"よろしく……！　お願いします！","ENG":"Pleased...! To meet you all!","TWN":"請……！請多指教！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으응, 우리야말로 잘 부탁해.","JPN":"うん、こっちこそよろしくね。","ENG":"We're pleased to meet you too!","TWN":"嗯，我們這邊才要請你多幫忙。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런데… 그 사고는 수업시간에 숨어서 땡땡이를 치던 이디스 선배 잘못이 크지 않아? 업보라고 생각하는데.","JPN":"でもさ……あの事故は、授業中に隠れてサボってたイーディス先輩が悪いんじゃない？　自業自得だと思うんだけど。","ENG":"But... Wasn't that accident more Edith's fault because she was skipping class? I think it's karma coming to bite you back.","TWN":"不過……那場意外不應該是翹課躲起來的伊蒂絲學姐的錯嗎？我覺得算是現世報。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"땡땡이라니, 표현이 잘못됐어.","JPN":"サボるという表現は間違ってる。","ENG":"Skipping class? That's incorrect.","TWN":"什麼翹課，你這個說法不太正確。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"내 꿈은 인류가 수평비행을 하는 의자 위에서 편안한 숙면을 가질 수 있게 되는 거야. 난 그런 인류의 미래를 위해 몸소 시험을 하고 있었을 뿐이라구우.","JPN":"私の夢は、人類が水平飛行をする椅子の上で安眠できるようになること。私はそんな人類の未来のために、体を張って実験をしてただけだよ。","ENG":"My dream is that mankind will be able to sleep comfortably on a chair that flies horizontally. And I was personally conducting a test for the future of mankind.","TWN":"我的夢想，是讓人類能在水平飛行的椅子上安穩入睡。我只是親自在為人類的未來進行測試而已啦。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런 꿈 얘기 처음 듣거든? 케이시를 데려온 것도 결국 선배가 일하기 귀찮아서 그런 거 아냐?","JPN":"そんな夢の話初耳なんですけど～？　ケイシーちゃんを連れてきたのも、結局先輩が働きたくないからじゃないの？","ENG":"That's the first time I ever heard about such a dream. But didn't you bring Kaci along because you're too lazy and don't want to work?","TWN":"我還是第一次聽說這種夢想耶？你帶卡西來，該不會只是因為學姐不想工作吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아, 아니에요! 이디스 선배는 괜찮다고 했지만, 제가 억지로 돕고 싶다고 한걸요!","JPN":"ち、違います！　イーディス先輩は必要ないって言ったのに、あたしが無理を言って手伝わせてもらってるんです！","ENG":"N-no! Edith said I didn't have to, but I insisted I wanted to help!","TWN":"不、不是的！雖然伊蒂絲學姐說沒關係，是我自己硬要來幫忙的！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"…그으래?","JPN":"……そ～お？","ENG":"...Is that so?","TWN":"……是嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아무튼, 오늘 두 사람이 맡아줘야 할 일을 알려 줄게.","JPN":"とにかく、今日二人にお願いしたいことを教えるね。","ENG":"Anyway, I'll tell you two what tasks you'll be doing today.","TWN":"總之，我來說明一下今天你們兩個要負責的工作。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그쪽은 어때~?","JPN":"そっちはどう～？","ENG":"How does it look on your side?","TWN":"那邊怎麼樣～？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"문제없어요. 송수관이 막힌 건 아닌 것 같아요.","JPN":"問題ありません。送水管が詰まっているわけではないみたいです。","ENG":"No problems. I don't think the water pipe is clogged.","TWN":"沒問題，看起來不是水管堵塞。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그럼, 수영장 물이 안 나오는 원인은 급수시스템의 고장일 가능성이 높아.","JPN":"じゃあ、プールの水が出ない原因は、給水システムに問題が生じた可能性が高いね。","ENG":"Then, there is a high possibility that the cause of the pool water not coming out is a malfunction in the water supply system.","TWN":"那麼泳池沒水的原因，很可能是供水系統故障。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"인공지능이 고장 나서 원격으로 점검할 수 없는 상태이니, 직접 설비 안으로 들어가서 확인해야 할 거야.","JPN":"人工知能が壊れたせいで、リモート点検ができない状態だから、直接設備に入って確かめてみないと。","ENG":"Since the AI's down and we can't do a remote inspection, we'll have to go into the facility and check it out ourselves.","TWN":"因為人工智慧壞了，現在沒辦法遠端檢查，只能直接進入設備確認了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네! 제가 안으로 들어가볼게요!","JPN":"はい！　あたしが中に入ってみます！","ENG":"Okay! I'll take a look inside!","TWN":"是！我進去看看！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"조명이 없어서 어두울 텐데~ 혼자 무섭지 않겠어?","JPN":"光がないから暗いと思うけど～1人で怖くない？","ENG":"It's going to be pitch-dark without any lights. Won't you be scared of being all alone in there?","TWN":"裡面沒有照明，會很暗喔～你一個人不會怕嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"괜찮아요. 익숙해서 오히려 편하거든요, 그런 거.","JPN":"大丈夫です。慣れてるので、むしろ気持ちが落ち着くんです。","ENG":"I'm all right. I'm used to places like this, so it's actually quite comfortable.","TWN":"沒關係，我習慣了，反而覺得很自在。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐음, 그렇구나- 케이시는 어둠 속에서 끔찍한 괴물이 튀어나와도 놀라지 않는 타입이구나.","JPN":"ふーん、そっか。ケイシーは闇の中から恐ろしい化け物が出てきても驚かないタイプなんだね。","ENG":"Hmm, I see. So Kaci's not the type to get startled when a scary monster jumps out from the dark.","TWN":"哦～原來如此。卡西是那種就算在黑暗中有可怕怪物跳出來，也不會嚇到的類型啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그렇게 말씀하시니까 갑자기 무서워졌어요.","JPN":"そう言われたら……急に怖くなりました。","ENG":"Well, now that you say it like that, I'm scared.","TWN":"你這麼說，我突然開始害怕了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"안으로 들어왔어요. 어떻게 할까요?","JPN":"中に入りました。これからどうしましょうか？","ENG":"I'm in. What should I do next?","TWN":"我進來了，接下來要怎麼做？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L30_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"파이프를 따라 움직이면 수동조작이 가능한 계기판이 보일 거야.","JPN":"パイプをたどって行けば、手動操作できる計器盤が見えるはずだよ。","ENG":"Move along the pipe and you'll see a panel that can be manually operated.","TWN":"沿著管線走，你會看到可以手動操作的控制面板。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"여기… 생각보다 어둡고 넓네요.","JPN":"ここ……思ったより暗くて、広いんですね。","ENG":"It's... darker and more spacious in here than I thought.","TWN":"這裡……比想像中還暗又大呢。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"어둠 속에서 부기맨이 손을 뻗어올지도 모른다구?","JPN":"闇の中からブギーマンが手を伸ばしてくるかもしれないよ？","ENG":"A boogeyman might reach his hand out to you from the dark.","TWN":"說不定會有躲在黑暗中的怪物伸出手喔？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그, 그렇게까지 말씀하실 필요 있는 건가요…?","JPN":"そ、そんなこと言う必要ありますか……？","ENG":"D-did you have to say that to me...?","TWN":"有、有必要說得這麼恐怖嗎……？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"미안. 분위기전환용으로 말해봤어.","JPN":"ごめん。雰囲気を変えるつもりで言ってみただけ。","ENG":"Sorry. I was trying to change the mood a bit.","TWN":"抱歉，我只是想轉換一下氣氛。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그치만 조심해~ 얼마전에 그쯤에서 생체반응이 감지된 적이 있거든.","JPN":"でも気をつけてね～この前、その辺りで生体反応が感知されたことがあるからね。","ENG":"But be careful! There was a bio signal detected around there recently.","TWN":"不過要小心喔～前陣子這附近曾偵測到生命反應。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네…?","JPN":"えっ……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"으으… 정말로 부기맨이 나타나면 어떡하죠?","JPN":"うう……本当にブギーマンが現れたらどうしましょう？","ENG":"Ngh... What do I do if a boogeyman really does come out?","TWN":"嗚……如果真的出現怪物怎麼辦？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"뭐어- 부기맨은 일반인을 상대로 하는 괴담이니까- 카운터인 케이시의 펀치 한 방이면 해치우지 않을까 싶은데.","JPN":"まあ～ブギーマンは大衆向けの怪談だし～ケイシーはカウンターだからパンチ一発で倒せるんじゃないかな。","ENG":"Well, because the boogeyman is an urban legend to scare non-Counters. And since you're a Counter, you can defeat it with just one punch, Kaci.","TWN":"唉唷～怪物本來就是嚇唬普通人的怪談啦～身為制裁者的卡西，一拳就能解決吧？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"해… 해치울게요! 뭔가 나타나면 펀치로…!","JPN":"た……倒します！　何かが現れたらパンチで……！","ENG":"I-I'll try! If anything pops up, I'll punch it, and–!","TWN":"我、我會解決的！如果出現的話，就用拳頭……！"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"으히이이익?!","JPN":"ひいいいいっ！？","ENG":"EEEEK?!","TWN":"咿呀啊啊？！"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"무슨 일이야~?","JPN":"どうしたの～？","ENG":"What's going on?","TWN":"怎麼了～？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"바 바바, 방금… 안쪽에서 무슨 소리가 났어요.","JPN":"い、いい、今……奥の方から何か音がしました。","ENG":"I-I heard something coming from inside.","TWN":"剛、剛剛……裡面好像有什麼聲音。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저기… 만약에… 정말로 부기맨이라면…","JPN":"あの……もし……本当にブギーマンだったら……","ENG":"Um... If there... really is a boogeyman...","TWN":"那個……如果……如果真的是怪物……"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"제가… 이길 수 있을까요?","JPN":"あたし……勝てるんでしょうか？","ENG":"do you think... I can win?","TWN":"我……打得過嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"으음, 펀치는 되도록 안 쓰는 게 좋다고 생각해.","JPN":"うーん、パンチはなるべく控えたほうがいいと思う。","ENG":"Mm, I think it would be best if you don't punch it.","TWN":"嗯，我覺得最好不要用拳頭。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"요즘은 상상 속의 캐릭터들을 폭행하는 것도 유죄가 될 수 있거든.","JPN":"最近は、架空のキャラクターに暴力を振るうことも有罪になるんだよ。","ENG":"These days, even assaulting imaginary characters is considered a crime.","TWN":"最近連毆打虛擬角色，都有可能構成犯罪喔。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그, 그런가요?","JPN":"そ、そうなんですか？","ENG":"R-really?","TWN":"是、是這樣嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"어…?","JPN":"あれ……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"꺄아아!! 방금 제 머리 위로 뭔가 움직임이…!","JPN":"キャアアア！！　今、何か頭の上で動きました！","ENG":"KYAAAH!! Something just moved above my head...!","TWN":"呀啊啊！！剛剛有東西從我頭上跑過去了……！"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"퍼, 펀치…! 펀치를 허가해주세요! 이디스 선배님!","JPN":"ぱ、パンチ……！　パンチを許可してください！　イーディス先輩！","ENG":"P-punch...! Let me punch it, Edith!","TWN":"拳、拳頭……！請允許我使用拳頭！伊蒂絲學姐！"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"진정해, 케이시.","JPN":"落ち着いて、ケイシー。","ENG":"Relax, Kaci.","TWN":"冷靜點，卡西。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"방금 설비 밖으로 작은 새 한 마리가 날아갔을 뿐이야.","JPN":"今のは設備の外に、小さな鳥が飛んで行っただけだから。","ENG":"It was just a bird that flew out of the facility.","TWN":"剛剛只是有一隻小鳥飛出設備而已。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"새… 였군요.","JPN":"鳥……だったんですね。","ENG":"It was... a bird.","TWN":"原來是……鳥啊。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"휴우…….","JPN":"ふう……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"앗? 이건…?","JPN":"あっ、これは……？","ENG":"Huh? What's this...?","TWN":"咦？這是……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"오, 계기판 찾은 거야?","JPN":"あ、計器盤見つかった？","ENG":"Oh, did you find the operation panel?","TWN":"哦，你找到控制面板了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…아뇨.","JPN":"……いえ。","ENG":"...No.","TWN":"……不是。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"설비가 고장 난 원인… 찾은 것 같아요.","JPN":"設備が壊れた原因……を見つけました。","ENG":"But I think I found the cause... of the malfunction.","TWN":"我好像找到……設備故障的原因了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"잠시만요. 사진 보내드릴게요.","JPN":"ちょっと待っててくださいね。写真を送ります。","ENG":"Hold on. I'll send you a photo.","TWN":"等我一下，我把照片傳給你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"응…? 이건 새 둥지잖아?","JPN":"ん……？　鳥の巣？","ENG":"Hmm? That's a bird's nest.","TWN":"嗯……？這不是鳥巢嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"귀엽지 않나요? 작은 알도 들어있어요.","JPN":"可愛くないですか？　小さな卵も入っています。","ENG":"Isn't it cute? There are even tiny eggs in it.","TWN":"很可愛吧？裡面還有小小的蛋呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"다행이네요. 말씀하신 생체반응의 정체가 부기맨은 아니라서요.","JPN":"よかったですね。イーディス先輩が言っていた生体反応の正体は、ブギーマンじゃないようです。","ENG":"Well at least we now know that the bio signals weren't from a boogeyman.","TWN":"太好了，原來你說的生命徵象不是怪物。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"헤, 진짜로 믿고 있었구나. 케이시는 순수하네.","JPN":"へえ、本当に信じてたんだ。ケイシーはピュアだね。","ENG":"Heh, did you really believe me? You're so naive, Kaci.","TWN":"嘿，你居然真的相信了啊？卡西還真單純。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"노, 놀리지 마세요.","JPN":"か、からかわないでください。","ENG":"D-don't make fun of me.","TWN":"別、別取笑我啦。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그런데… 어쩌다 새가 이런 곳에 둥지를 짓게 된 걸까요?","JPN":"でも……どうしてこんなところに巣を作ったんでしょうか？","ENG":"But... how did a bird even build a nest in a place like this?","TWN":"不過……為什麼鳥會跑到這種地方築巢呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"아마도 안전한 곳을 찾아서 여기까지 왔을 거야.","JPN":"多分、安全な場所を探してたらそこが見つかったんだろうね。","ENG":"I'm guessing it came here looking for a safe place.","TWN":"大概是為了尋找安全的地方，才一路來到這裡吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"새들은 원래 나뭇잎이 무성한 나무에 집을 짓고 살지만, 이젠 그런 멀쩡한 나무가 별로 없으니까.","JPN":"鳥って、元々葉が生い茂る木の上に巣を作るけど、そんなまともな木はもうほぼなくなってしまったから。","ENG":"Although birds usually build their nests in trees with lush leaves, there aren't many good trees these days.","TWN":"鳥本來都是在枝葉茂密的樹上築巢生活的，但現在這種完好的樹已經不多了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아… 수업시간에 배웠어요. 나무가 부족하다는 건… 침식현상 때문인 거죠?","JPN":"あ……授業で教わりました。木が少なくなったのは……侵食現象のせいですよね？","ENG":"Oh... I learned that in class. The lack of trees is... because of the Counterside Effect, right?","TWN":"啊……課堂上有教過。樹木變少是因為……侵蝕現象對吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"응~ 정답이야~","JPN":"うん。正解～","ENG":"Yup! That's correct.","TWN":"嗯～答對了～"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"우리 세대는 직접 경험한 적 없지만, 침식현상이 생겨난 이후로 생태계에 많은 변화가 있었다고 해.","JPN":"私たちの世代が直接経験したことではないけど、侵食現象が現れてから生態系に色んな変化があったらしい。","ENG":"Even though our generation never experienced it directly, the ecosystem is said to have changed a lot ever since the Counterside Effect occurred.","TWN":"雖然我們這一代沒有親身經歷過，據說自從侵蝕現象出現後，生態系統就產生了很大的變化。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"예전엔 따뜻한 곳을 찾아 무리 지어 집을 옮겨 다니는 철새라는 개념도 있었지만, 계절이 뒤죽박죽이 된 지금은 찾아볼 수 없게 된 광경이지.","JPN":"昔は、群れを作って温かい地域に移動する渡り鳥という存在がいたけど、季節がめちゃくちゃになった今の時代では見ることができなくなってしまったね。","ENG":"There used to be migratory birds that would fly in flocks relocating to warmer climates, but with the seasons all mixed up, it's something you can't see these days.","TWN":"以前還有為了尋找溫暖地區而成群遷徙的候鳥，但在季節變得一團亂的現在，已經很難再看到那種景象了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…안타깝네요. 새들이 편히 지낼 수 있는 나무가 부족하다는 건.","JPN":"……悲しいことですね。鳥たちがゆっくり休める木が足りないだなんて。","ENG":"...It's a shame that there aren't enough trees for birds to comfortably rest.","TWN":"……真可惜，連讓鳥安心生活的樹都變少了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"뭐어- 사람에게도 마찬가지지. 지금은 너도 나도 살 곳이 부족한- 그런 세상이니까.","JPN":"まあ～人間もそう変わらないよね。今は暮らせる場所が足りない、そういう世の中だから。","ENG":"Well, it's the same for people. We also don't have enough places to live. That's what the world has come to.","TWN":"嗯～對人類來說也一樣，現在是誰都缺乏棲身之處的世界。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"이제 이 둥지는 어쩌죠?","JPN":"ではこの巣はどうするんですか？","ENG":"What should I do with the nest?","TWN":"那這個巢該怎麼辦呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"설비를 고치려면 치우는 수밖에 없겠지.","JPN":"設備を直すためには、どかすしかないね。","ENG":"We'll have to remove it if we want to fix the facility.","TWN":"如果要修好設備，只能把它移走了吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네? 좀 더 안전한 장소로 둥지를 옮겨줘도 되지 않을까요?","JPN":"え？　もう少し安全な場所に巣を移してあげてもいいんじゃないですか？","ENG":"Huh? Shouldn't we move it to somewhere safer?","TWN":"咦？不能把鳥巢移到更安全的地方嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"별로 의미는 없을 거야. 한 번 위협을 느끼고 떠난 어미새는 다시 돌아올 가능성이 낮아.","JPN":"あまり意味はないと思うよ。一度危険を察知して離れた親鳥が戻ってくる可能性は低い。","ENG":"That won't help. Once the mother bird feels threatened and leaves, it is unlikely to return.","TWN":"意義不大。一旦感受到威脅而離開的母鳥，幾乎不會再回來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"더군다나 장소를 옮긴 둥지를 되찾아올 가능성은 더더욱 낮겠지.","JPN":"しかも巣を移したら、その可能性は更に低くなるだろうね。","ENG":"And more so if that nest has been relocated.","TWN":"更別說回來找被移走位置的巢，那個可能性就更低了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그렇군요.","JPN":"そうなんですね。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오, 왔구나. 두 사람 모두 고생했…","JPN":"あ、おかえり。2人ともおつかれ……","ENG":"Oh, you're back. Great work, you two–","TWN":"喔，你們回來啦。兩個人都辛苦……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 왜 이디스 선배 혼자 온 거야?","JPN":"ん？　なんでイーディス先輩だけなの？","ENG":"Hmm? Why did you come alone, Edith?","TWN":"咦？怎麼只有伊蒂絲學姐一個人？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"글쎄에- 케이시는 바쁜 일이 생겼다면서 혼자 가더라구.","JPN":"さあね～ケイシーは急ぎの用があるって先に帰っちゃった。","ENG":"Well, Kaci went off on her own saying that she was busy.","TWN":"對啊。卡西說突然有事，自己先走了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아쉽네. 후배가 학생회 일을 도와준다고 했더니 학생회장이 화과자도 준비해줬는데.","JPN":"残念だね。生徒会長に後輩が生徒会の仕事を手伝ってくれたって話したら、和菓子を用意してくれたのに。","ENG":"That's too bad. The Student President prepared us some snacks after she heard Kaci was helping us with Student Council work.","TWN":"真可惜。學生會長聽說學妹要幫學生會的忙，還準備了和菓子呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"과자. 내가 직접 전해주고 올게.","JPN":"それ、私が直接届けてくるよ。","ENG":"Snacks? I'll deliver them to her.","TWN":"點心……我親自送過去吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"정말? 돌아오자마자 잠들 줄 알았더니 웬일이래?","JPN":"本当に？　帰ってきたらすぐに寝るのかと思ってたけど。どうしたの？","ENG":"Really? I thought you'd go to sleep as soon as you came back. What's the occasion?","TWN":"真的？我還以為你一回來會倒頭就睡呢，怎麼這麼稀奇？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Um...","TWN":"唔嗯……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"좋아. 이러면 되겠지?","JPN":"よし。これでいいかな？","ENG":"Okay. This should do it, right?","TWN":"好，這樣應該可以了吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"오, 제법 쓸만한 간이부화기를 만들었네.","JPN":"へえ、簡易孵卵器？　中々いい出来だね。","ENG":"Oh, you made yourself a pretty good incubator.","TWN":"喔，你做了個挺像樣的簡易孵化器呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"힉-!","JPN":"ひっ！？","ENG":"Heek!","TWN":"哇！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"이, 이디스 선배님? 언제 오셨어요?","JPN":"い、イーディス先輩？　いつの間に来たんですか？","ENG":"E-Edith? When did you get here?","TWN":"伊、伊蒂絲學姐？！你什麼時候來的？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"과자 전해주러 왔어. 학생회장이 준 거야.","JPN":"お菓子届けに来たよ。生徒会長からの差し入れ。","ENG":"I came to give you some snacks from the Student President.","TWN":"我來送學生會長給的點心。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"오는 길에 먹어서 반 밖에 안 남았지만.","JPN":"ここに来る途中で食べちゃったから、半分しか残ってないけど。","ENG":"But I ate some along the way, so there's only half of them left.","TWN":"不過我在路上吃掉了一半，只剩這些了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아… 감사합니다.","JPN":"あ……ありがとうございます。","ENG":"Oh... thank you.","TWN":"啊……謝謝你。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그 알, 버리지 않았네.","JPN":"その卵、捨ててなかったんだね。","ENG":"Those eggs, you didn't throw them away.","TWN":"你沒有丟掉那顆蛋呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…네, 일단은 제 실수이니까요. 제가 책임지고 싶어요.","JPN":"……はい。あたしのミスですから。責任を取りたいんです。","ENG":"...No. It's my fault, so I wanted to take the responsibility.","TWN":"……對。畢竟是我的失誤，我想自己負起責任。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"네가 일부러 그런 것도 아니잖아. 어쩔 수 없는 일이었어.","JPN":"君がわざとやったことじゃないじゃん。仕方ないことだったんだし。","ENG":"But you didn't do it on purpose. It couldn't be helped.","TWN":"你也不是故意的，那是沒辦法的事。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그런 작은 일에 일일이 책임의식을 느끼면 나중에 많이 힘들어질걸?","JPN":"そんなことにいちいち責任を感じてたら、この先辛いことが増えるよ。","ENG":"If you keep feeling responsible for every little thing, it's going to get only harder for you.","TWN":"要是對這種小事都覺得有責任，之後會很累喔？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그럴 지도요. 하지만…","JPN":"そうかもしれません。でも……","ENG":"Maybe. But...","TWN":"也許吧。可是……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"전 그렇게 할 수 있으니까, 그러고 싶은걸요!","JPN":"あたしにできることですから、そうしたいんです！","ENG":"I can manage. Plus, I want to!","TWN":"我做得到，所以我想這麼做！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그거, 무정란일 수도 있어.","JPN":"それ、無精卵の可能性もあるよ。","ENG":"The eggs could be unfertilized.","TWN":"那顆蛋，也有可能是未受精的蛋。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아앗?! 그, 그런가요?!","JPN":"ええっ！？　そ、そうなんですか！？","ENG":"Oh?! R-really?","TWN":"欸？！是、是這樣嗎？！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"어, 어쩌지…? 저는 그런 줄도 모르고 혼자서 인터넷으로 열심히 부화기를… 부끄럽네요.","JPN":"ど、どうしよう……？　あたし、そんなことも知らずにネットで孵卵器の勉強を……恥ずかしいです。","ENG":"W-what do I do...? I didn't think about that and searched the internet for making an incubator... I feel silly now.","TWN":"怎、怎麼辦……？我不知道有可能會這樣，還一個人上網認真做了孵化器……好丟臉。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"내 말은- 알에서 아무것도 태어나지 않더라도 너무 상심하지 말란 뜻이야.","JPN":"だから、卵から何も生まれなくても、あまり落ち込む必要はないってことだよ。","ENG":"What I mean is, don't get too discouraged if the eggs don't hatch.","TWN":"我不是那個意思—我是說就算蛋裡沒有孵出任何東西，也不要太難過。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그 알이 남겨진 건, 네 잘못이 아니니까.","JPN":"その卵が残されたのは、君のせいじゃないから。","ENG":"It's not your fault that the eggs were left behind.","TWN":"那顆蛋會被留下來，並不是你的錯。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"걱정해주셔서 고맙습니다, 선배님.","JPN":"心配してくれてありがとうございます、先輩。","ENG":"Thank you for your concern, Edith.","TWN":"謝謝你關心我，學姐。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그 알… 만약에 깨어나면, 지낼 수 있는 나무가 필요하겠네.","JPN":"その卵……もし孵化したら、鳥が住む木が必要になるね。","ENG":"But... if it does hatch, we'll need a tree for it to live on.","TWN":"如果那顆蛋孵化了……就需要能生活的樹了呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아… 아무래도 그렇겠죠?","JPN":"あ……確かにそうですね。","ENG":"I... guess so?","TWN":"啊……好像是這樣喔？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"날개가 있으니까… 새장에서 자라는 것보다, 더 넓은 곳에서 지내게 해주고 싶어요.","JPN":"翼があるから……鳥かごじゃなくて、もっと広い場所に住まわせてあげたいです。","ENG":"It has wings, so... I want it to live in a bigger place than inside a bird cage.","TWN":"既然有翅膀……比起在鳥籠裡長大，我更希望牠能在更寬廣的地方生活。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐으음-","JPN":"ふーむ……","ENG":"Hmm...","TWN":"唔嗯—"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"나한테 좋은 생각이 있어.","JPN":"私にいいアイデアがある。","ENG":"I have a good idea, then.","TWN":"我有個好主意。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"좋은 생각이요…?","JPN":"いいアイデア……？","ENG":"A good idea?","TWN":"好主意……？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"여기가… 아카데미의 뒤뜰…?","JPN":"ここが……アカデミーの裏庭……？","ENG":"This is... the Academy's backyard...?","TWN":"這裡是……學院的後院……？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"엄청나게 넓네요.","JPN":"すごく広いですね。","ENG":"It's so spacious.","TWN":"好大啊。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"응, 하지만 있는 거라고는 흙 밖에 없는 공터야. 아무것도 자라지 않았지.","JPN":"うん。でも土しかない空地だよ。何も育ってない。","ENG":"Yeah. But it's empty with nothing but dirt. Nothing has grown here.","TWN":"嗯，不過這片空地只有土，什麼都沒長。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"지금부터 여길 꽃꽂이부의 부장인 케이시에게 맡길게.","JPN":"今からここを、華道部の部長ケイシーに任せる。","ENG":"From now on, I'll leave you, the leader of the Flower Arrangement Club, in charge of this place.","TWN":"從現在開始，我把這裡交給插花部的部長卡西來管理。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네…? 그래도 괜찮은 건가요?","JPN":"え……？　いいんですか？","ENG":"What...? Are you sure that's all right?","TWN":"咦……？真的可以嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"응- 여기선 나무든 꽃이든 원하는대로 길러도 돼.","JPN":"うん。ここでは木でも花でも、好きなだけ育てていいよ。","ENG":"Yeah. You can plant flowers and trees as you like here.","TWN":"嗯—不管是樹還是花，在這裡隨便你種。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"새들이 둥지를 짓고 쉴 만큼 큰 나무는 금방 자라기 어렵겠지만-","JPN":"木を植えても、鳥たちが巣を作れるほど大きくなるのは、ずいぶん先のことになるだろうけど。","ENG":"It'll take some time before the trees are tall enough for birds to make nests and rest on them, but...","TWN":"雖然短時間內可能無法長出能讓鳥築巢、休息的大樹—"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"원래 뭐든 새싹부터 천천히 시작하는 거니까.","JPN":"どんなものでも小さな苗からゆっくり育つもんね。","ENG":"Everything starts slow and from a sprout.","TWN":"但無論是什麼，都是從嫩芽開始慢慢成長的。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네! 저 열심히 키워볼게요!","JPN":"はい！　あたし、頑張って育ててみます！","ENG":"Okay! I'll do my best to grow them!","TWN":"是！我會努力培育的！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"꽃도! 나무도! 그리고… 아기새도요!","JPN":"花も！　木も！　そして……雛鳥も！","ENG":"Flowers! Trees! And... even the baby birds!","TWN":"花也好！樹也好！還有……小鳥也是！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"좋아. 그럼 결정이네.","JPN":"よし。じゃあ決まりだね。","ENG":"Okay. Then it's settled.","TWN":"好，那就這麼決定了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"…라면서 뒤뜰 관리를 케이시한테 떠넘겼다고?","JPN":"……それで、裏庭の管理をケイシーちゃんに任せたと？","ENG":"...And so, you handed the responsibility of taking care of the backyard to Kaci?","TWN":"……所以你就這樣把後院全丟給卡西管理了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Yeah.","TWN":"嗯。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"선배 말이야! 사람이 아무리 게을러도 그렇지! 그런 큰 땅을 초등부 한 명한테 맡기는 게 말이 돼?!","JPN":"先輩ったら！　いくらサボりたいからって、あんな広い土地を初等部の子ども1人に任せるなんてありえないでしょ！","ENG":"C'mon! Even if you're that lazy! How can you let just one elementary school student be in charge of that large piece of land?!","TWN":"學姐你也太誇張了吧！再怎麼懶，也不能把那麼大一塊地交給一個小學部學生啊？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"하암- 난 별로 뭘 가꾸는 재주는 없어서.","JPN":"ふああ～でも私、何か育てるのは得意じゃないから。","ENG":"*Yawn* I don't have a green thumb.","TWN":"喔—我又不擅長照顧東西。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그리고 사람은- 자기마다 적성이 있는 법이니까.","JPN":"得意分野は人それぞれなんだし。","ENG":"And everyone... has their own aptitude.","TWN":"而且人啊—本來就各有所長嘛。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"하아, 지금 그걸 핑계라고…","JPN":"はあ、なんて言い訳……","ENG":"*Sigh* What a lousy excuse...","TWN":"喂，你現在是在找藉口吧……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"역시 아닌 것 같아. 지금이라도 이 결정은 철회를 하는 편이…","JPN":"やっぱりこれはだめだと思います。今からでもこの話は撤回したほうが……","ENG":"I don't think this is right. We should withdraw the decision and–","TWN":"果然不太對勁，現在撤回這個決定還來得及……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"맡겨보도록 하죠.","JPN":"任せてみましょう。","ENG":"Let's see how she does first.","TWN":"就交給她吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회장?","JPN":"生徒会長？","ENG":"Student President?","TWN":"學生會長？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그치만 걘 아직 초등부인데?","JPN":"でもあの子はまだ初等部ですよ？","ENG":"But she's only an elementary school student.","TWN":"可是她還只是小學部耶？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여긴 카운터 아카데미입니다.","JPN":"ここはカウンターアカデミーです。","ENG":"This is the Counter Academy.","TWN":"這裡是制裁者學院。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"당사자가 원한다면, 되도록 많은 기회를 주는 편이 자신의 적성을 찾기 쉬우니까요.","JPN":"本人が望むのであれば、なるべく多くのチャンスを与えたほうが、自分の適正を早く見つけられる。","ENG":"If she wants to do it, then I think it's best to give her more opportunities to discover what her strengths are.","TWN":"只要當事人有意願，給予更多機會，反而能讓他們更容易找到自己的定位。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회장이 그렇게까지 말한다면, 나야 이견은 없지만…","JPN":"生徒会長がそこまでいうなら、あたしも反対しないけど……","ENG":"Well, if you say so, I won't disagree, but...","TWN":"既然學生會長都這麼說了，我是沒意見啦……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이디스 선배! 정말로 귀찮으니까 말로 구슬려서 떠넘긴 거 아니지?","JPN":"イーディス先輩！　めんどくさいからって言いくるめて適当に押しつけたわけじゃないんですよね！","ENG":"Edith! You didn't coax her because you were too lazy to do it, right?","TWN":"伊蒂絲學姐！你該不會真的只是嫌麻煩，才用話術丟給她吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"음냐아…","JPN":"むにゃ……","ENG":"*Yawn*","TWN":"呼啊……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"뭘 벌써 잠들고 있는 거야!","JPN":"寝るの早すぎでしょ！！","ENG":"She's already asleep?!","TWN":"你怎麼已經睡著了！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"일어나! 아직 우리 해야 할 업무가 많다고!","JPN":"起きてください！　まだ仕事が山積みなんですよ！","ENG":"Wake up! We still have work to do!","TWN":"快起來！我們還有一堆工作要做呢！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};